          proxyTermsJson == other.proxyTermsJson;
}

/// The wallet's own public Orchard half + hashlock commitment for `swap_id` —
/// what the wallet reports to the orderbook at Phase0 so the solver can derive
/// and verify the same joint UA. Hex-encoded.
class ZwapInitiatorHalf {
  final String akSec1;
  final String nskLe;

  /// `h_a = SHA256(k_a)` — published; `k_a` itself stays in the wallet.
  final String hAHex;

  /// `swap_hash = SHA256(secret)` — the lock's branch-1 commitment.
  final String swapHashHex;

  const ZwapInitiatorHalf({
    required this.akSec1,
    required this.nskLe,
    required this.hAHex,
    required this.swapHashHex,
  });

  @override
  int get hashCode =>
      akSec1.hashCode ^ nskLe.hashCode ^ hAHex.hashCode ^ swapHashHex.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is ZwapInitiatorHalf &&
          runtimeType == other.runtimeType &&
          akSec1 == other.akSec1 &&
          nskLe == other.nskLe &&
          hAHex == other.hAHex &&
          swapHashHex == other.swapHashHex;
}

/// Flat, FRB-friendly signed-tx result.
class ZwapSignedBtcTx {
  final String rawTxHex;
  final String txid;

  const ZwapSignedBtcTx({required this.rawTxHex, required this.txid});

  @override
  int get hashCode => rawTxHex.hashCode ^ txid.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is ZwapSignedBtcTx &&
          runtimeType == other.runtimeType &&
          rawTxHex == other.rawTxHex &&
          txid == other.txid;
}

