/// The z2b order `feMaterial` fields the wallet owns. Same shape as the b2z
/// inputs EXCEPT: z2b has NO `swap_hash` (the solver owns the secret), and the
/// FE-material `refundPubkey` field carries the user's per-swap BTC CLAIM pubkey
/// (`b_b`), not a refund key. `k_be_hex` is the hashbind prover input.
class ZwapZ2bOrderInputs {
  final String hA;
  final String akA;
  final String nskA;
  final String lockPubkey;

  /// The user's per-swap BTC claim pubkey `b_b` — posted as `refundPubkey`.
  final String claimPubkey;
  final String kBeHex;

  const ZwapZ2bOrderInputs({
    required this.hA,
    required this.akA,
    required this.nskA,
    required this.lockPubkey,
    required this.claimPubkey,
    required this.kBeHex,
  });

  @override
  int get hashCode =>
      hA.hashCode ^
      akA.hashCode ^
      nskA.hashCode ^
      lockPubkey.hashCode ^
      claimPubkey.hashCode ^
      kBeHex.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is ZwapZ2bOrderInputs &&
          runtimeType == other.runtimeType &&
          hA == other.hA &&
          akA == other.akA &&
          nskA == other.nskA &&
          lockPubkey == other.lockPubkey &&
          claimPubkey == other.claimPubkey &&
          kBeHex == other.kBeHex;
}

/// z2e claim sigs: complete the solver's `claim_buy` adaptor with the user's
/// `k_be` (→ sig_a recovering to `solver_claim_addr`) and sign the digest with
/// `k_be` (→ sig_b, the user's own). Returns both 65-byte sigs (hex); the caller
/// relays them + the preimage to the eth-relayer's `claim_buy`.
class ZwapZ2eClaimSigs {
  final String sigAHex;
  final String sigBHex;

  const ZwapZ2eClaimSigs({required this.sigAHex, required this.sigBHex});

  @override
  int get hashCode => sigAHex.hashCode ^ sigBHex.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is ZwapZ2eClaimSigs &&
          runtimeType == other.runtimeType &&
          sigAHex == other.sigAHex &&
          sigBHex == other.sigBHex;
}

