      hA.hashCode ^
      akA.hashCode ^
      nskA.hashCode ^
      lockPubkey.hashCode ^
      dleqProof.hashCode ^
      claimPubkey.hashCode ^
      kBeHex.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is ZwapZ2eOrderInputs &&
          runtimeType == other.runtimeType &&
          hA == other.hA &&
          akA == other.akA &&
          nskA == other.nskA &&
          lockPubkey == other.lockPubkey &&
          dleqProof == other.dleqProof &&
          claimPubkey == other.claimPubkey &&
          kBeHex == other.kBeHex;
}
